import{_ as a,o as t,c as s,ad as e}from"./chunks/framework.DdcUsuRQ.js";const u=JSON.parse('{"title":"APCA","description":"The Accessible Perceptual Contrast Algorithm shipped as APCA-W3 0.0.98G-4g. Signed Lc values, polarity-aware exponents, and the soft-clamp polynomial iridis uses.","frontmatter":{"title":"APCA","description":"The Accessible Perceptual Contrast Algorithm shipped as APCA-W3 0.0.98G-4g. Signed Lc values, polarity-aware exponents, and the soft-clamp polynomial iridis uses.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/apca"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/apca"}],["meta",{"property":"og:title","content":"APCA: iridis"}],["meta",{"property":"og:description","content":"The Accessible Perceptual Contrast Algorithm shipped as APCA-W3 0.0.98G-4g. Signed Lc values, polarity-aware exponents, and the soft-clamp polynomial iridis uses."}],["meta",{"name":"twitter:title","content":"APCA: iridis"}],["meta",{"name":"twitter:description","content":"The Accessible Perceptual Contrast Algorithm shipped as APCA-W3 0.0.98G-4g. Signed Lc values, polarity-aware exponents, and the soft-clamp polynomial iridis uses."}],["meta",{"name":"description","content":"The Accessible Perceptual Contrast Algorithm shipped as APCA-W3 0.0.98G-4g. Signed Lc values, polarity-aware exponents, and the soft-clamp polynomial iridis uses."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"APCA\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/apca\\"}]}"]]},"headers":[],"relativePath":"reference/apca.md","filePath":"reference/apca.md","lastUpdated":1779033869000}'),n={name:"reference/apca.md"};function r(d,i,p,o,c,l){return t(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="apca" tabindex="-1">APCA <a class="header-anchor" href="#apca" aria-label="Permalink to &quot;APCA&quot;">​</a></h1><p>APCA (Accessible Perceptual Contrast Algorithm) is a perceptually weighted contrast metric developed by Andrew Somers, intended as a successor to WCAG 2.x luminance contrast. It is the algorithm being evaluated for inclusion in WCAG 3. <span class="iridis-brand">iridis</span> ships APCA-W3 0.0.98G-4g (<code>packages/core/src/math/ContrastApca.ts</code>).</p><h2 id="why-apca" tabindex="-1">Why APCA <a class="header-anchor" href="#why-apca" aria-label="Permalink to &quot;Why APCA&quot;">​</a></h2><p>WCAG 2.1&#39;s ratio is symmetric and treats foreground and background interchangeably. In practice, dark text on a light background and light text on a dark background do not need the same contrast to read equally well, the eye is asymmetric. WCAG 2.1 is also a poor predictor at the dark end of the scale, where small differences in luminance compress into large differences in ratio.</p><p>APCA addresses both. It uses different exponents for text and background, returns a signed value that records polarity, and produces a number that maps more directly to the practical question &quot;is this text readable at this size and weight&quot;.</p><h2 id="lc" tabindex="-1">Lc <a class="header-anchor" href="#lc" aria-label="Permalink to &quot;Lc&quot;">​</a></h2><p>The output is Lc, <em>lightness contrast</em>, a signed value, conventionally reported with a magnitude on roughly <code>[0, 108]</code>.</p><table tabindex="0"><thead><tr><th>Lc sign</th><th>Meaning</th></tr></thead><tbody><tr><td>Positive</td><td>light background, dark text</td></tr><tr><td>Negative</td><td>dark background, light text</td></tr><tr><td>Zero</td><td>below the noise floor; treated as no readable contrast</td></tr></tbody></table><p>Magnitudes:</p><table tabindex="0"><thead><tr><th>Surface</th><th>Lc magnitude</th></tr></thead><tbody><tr><td>Small body text (under 14 pt thin / 12 pt regular)</td><td>≥ 75</td></tr><tr><td>Fluent body text (normal sizes)</td><td>≥ 60</td></tr><tr><td>Large text and headlines</td><td>≥ 45</td></tr><tr><td>Non-text icons and graphical components</td><td>≥ 30</td></tr></tbody></table><h2 id="the-math" tabindex="-1">The math <a class="header-anchor" href="#the-math" aria-label="Permalink to &quot;The math&quot;">​</a></h2><p>APCA computes per-side luminance with separate exponents, then takes the difference and applies clamping and scaling.</p><h3 id="soft-clamp" tabindex="-1">Soft clamp <a class="header-anchor" href="#soft-clamp" aria-label="Permalink to &quot;Soft clamp&quot;">​</a></h3><p>For each side, Y_soft applies a polynomial clamp at the dark end:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>Y_soft = Y                                        if Y ≥ 0.022</span></span>
<span class="line"><span>       = Y + (0.022 − Y) ^ 1.414                   otherwise</span></span></code></pre></div><p>The clamp suppresses runaway sensitivity to tiny absolute luminances near pure black.</p><h3 id="asymmetric-weighting" tabindex="-1">Asymmetric weighting <a class="header-anchor" href="#asymmetric-weighting" aria-label="Permalink to &quot;Asymmetric weighting&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>Y_text = 0.2126729 · R_lin^0.56  +  0.7151522 · G_lin^0.56  +  0.0721750 · B_lin^0.56</span></span>
<span class="line"><span>Y_bg   = 0.2126729 · R_lin^0.65  +  0.7151522 · G_lin^0.65  +  0.0721750 · B_lin^0.65</span></span></code></pre></div><p>The exponents differ, 0.56 for text, 0.65 for background, which is what gives APCA its asymmetry. The Rec. 709 luminance coefficients are unchanged.</p><h3 id="difference-and-scale" tabindex="-1">Difference and scale <a class="header-anchor" href="#difference-and-scale" aria-label="Permalink to &quot;Difference and scale&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>if bg_clamped &gt; text_clamped:</span></span>
<span class="line"><span>    Lc = (bg_clamped^0.56 − text_clamped^0.57) · 1.14</span></span>
<span class="line"><span>    if Lc &lt; 0.001:  return 0</span></span>
<span class="line"><span>    Lc = Lc − 0.027</span></span>
<span class="line"><span>else:</span></span>
<span class="line"><span>    Lc = (bg_clamped^0.62 − text_clamped^0.65) · 1.14</span></span>
<span class="line"><span>    if Lc &gt; −0.001:  return 0</span></span>
<span class="line"><span>    Lc = Lc + 0.027</span></span>
<span class="line"><span></span></span>
<span class="line"><span>return Lc · 100</span></span></code></pre></div><p>Two branches: one for normal-polarity (light bg, dark text), one for reverse-polarity (dark bg, light text). Each branch applies its own exponent pair and offset. The final multiply by 100 puts Lc on the conventional scale.</p><p>The constants in <code>ContrastApca.ts</code> (<code>SA98G_NORM_BG</code>, <code>SA98G_NORM_TXT</code>, <code>SA98G_CLAMP</code>, <code>SA98G_CLAMP_P</code>, <code>SA98G_SCALE</code>, <code>SA98G_LOW_CLIP</code>, <code>SA98G_OFFSET</code>) are the canonical APCA-W3 0.0.98G-4g values from the Myndex SAPC reference.</p><h2 id="math-primitive" tabindex="-1">Math primitive <a class="header-anchor" href="#math-primitive" aria-label="Permalink to &quot;Math primitive&quot;">​</a></h2><p><code>contrastApca</code> is exported as a singleton from <code>@studnicky/iridis</code> (<code>packages/core/src/math/ContrastApca.ts</code>) and called directly:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">import</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> {</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> contrastApca </span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">}</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);"> from</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;@studnicky/iridis&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);">const</span><span style="--shiki-light:var(--iridis-syntax-constant);--shiki-dark:var(--iridis-syntax-constant);"> lc</span><span style="--shiki-light:var(--iridis-syntax-keyword);--shiki-dark:var(--iridis-syntax-keyword);"> =</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> contrastApca</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">.</span><span style="--shiki-light:var(--iridis-syntax-function);--shiki-dark:var(--iridis-syntax-function);">apply</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">(</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);">text</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> background</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">);</span></span></code></pre></div><p>Both arguments are <code>ColorRecord</code> instances. The primitive reads the <code>rgb</code> field of each (sRGB-safe, gamut-mapped if the source OKLCH lay outside sRGB) and returns a signed <code>Lc</code> value.</p><h2 id="where-it-appears" tabindex="-1">Where it appears <a class="header-anchor" href="#where-it-appears" aria-label="Permalink to &quot;Where it appears&quot;">​</a></h2><ul><li><code>enforce:contrast</code> (<code>packages/core/src/tasks/enforce/EnforceContrast.ts</code>) routes pairs whose <code>algorithm</code> is <code>&#39;apca&#39;</code> to <code>contrastApca.apply(text, background)</code> and uses the absolute value of <code>Lc</code> against the pair&#39;s <code>minRatio</code>.</li><li><code>enforce:apca</code> in the contrast plugin (<code>packages/contrast/src/tasks/</code>) provides a wrapper that applies APCA threshold tables to pairs without each pair restating the magnitude.</li><li>A role schema selects APCA per pair:</li></ul><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:var(--iridis-syntax-function);--shiki-dark:var(--iridis-syntax-function);">contrastPairs</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> [</span></span>
<span class="line"><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">  {</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> foreground</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;text&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> background</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;canvas&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> minRatio</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-number);--shiki-dark:var(--iridis-syntax-number);"> 60</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">,</span><span style="--shiki-light:var(--iridis-syntax-text);--shiki-dark:var(--iridis-syntax-text);"> algorithm</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">:</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> &#39;apca&#39;</span><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);"> },</span></span>
<span class="line"><span style="--shiki-light:var(--iridis-syntax-punctuation);--shiki-dark:var(--iridis-syntax-punctuation);">]</span></span></code></pre></div>`,30)])])}const y=a(n,[["render",r]]);export{u as __pageData,y as default};
